var COURSE_SW_PL = [{day: 1, title: `Salamu za kwanza`, title_native: `Pierwsze powitania`, focus: `Leo unaanza na maneno ya msingi ya kusalimia ukiwa Warsaw au Kraków. Lengo ni kuweza kuingia dukani, hoteli au mkahawani kwa heshima.`, vocab: [{pl: `cześć`, sw: `hujambo / habari`, ipa: `cheshch`},{pl: `dzień dobry`, sw: `habari za mchana / shikamoo`, ipa: `jen DOH-bri`},{pl: `dobry wieczór`, sw: `habari za jioni`, ipa: `DOH-bri VYEH-choor`},{pl: `do widzenia`, sw: `kwaheri`, ipa: `doh vee-DZEH-nya`},{pl: `proszę`, sw: `tafadhali / karibu`, ipa: `PROH-sheh`},{pl: `dziękuję`, sw: `asante`, ipa: `jen-KOO-yeh`},{pl: `tak`, sw: `ndiyo`, ipa: `tahk`},{pl: `nie`, sw: `hapana`, ipa: `nyeh`},{pl: `przepraszam`, sw: `samahani`, ipa: `psheh-PRAH-sham`},{pl: `Polska`, sw: `Poland`, ipa: `POL-skah`}], phrases: [{pl: `Cześć!`, sw: `Hujambo!`, ipa: `cheshch`},{pl: `Dzień dobry.`, sw: `Habari za mchana.`, ipa: `jen DOH-bri`},{pl: `Dobry wieczór.`, sw: `Habari za jioni.`, ipa: `DOH-bri VYEH-choor`},{pl: `Do widzenia.`, sw: `Kwaheri.`, ipa: `doh vee-DZEH-nya`},{pl: `Dziękuję bardzo.`, sw: `Asante sana.`, ipa: `jen-KOO-yeh BAR-dzoh`},{pl: `Przepraszam, nie rozumiem.`, sw: `Samahani, sielewi.`, ipa: `psheh-PRAH-sham nyeh roh-ZOO-myem`}], grammar: `Katika Kipolishi, salamu hubadilika kulingana na muda na hali. “Cześć” ni ya kawaida na ya kirafiki, lakini “Dzień dobry” ni salama zaidi kwa watu usiowajua. “Proszę” inaweza kumaanisha “tafadhali,” “karibu,” au hutumika unapompa mtu kitu.`, practice: [`Sema “habari za mchana” kwa Kipolishi.`,`Jifunze kutofautisha “tak” na “nie.”`,`Andika salamu mbili rasmi na moja isiyo rasmi.`,`Tunga sentensi fupi ukisema hujaelewa.`,`Fanya mazoezi ya kusema “dziękuję bardzo” mara tano kwa sauti.`]},{day: 2, title: `Kujitambulisha`, title_native: `Przedstawianie się`, focus: `Ukiwa Gdańsk au Poznań, unaweza kukutana na mwenyeji, mhudumu au msafiri mwingine. Leo utajifunza kusema jina lako na kuuliza jina la mtu mwingine.`, vocab: [{pl: `ja`, sw: `mimi`, ipa: `yah`},{pl: `ty`, sw: `wewe`, ipa: `tih`},{pl: `pan`, sw: `bwana / wewe rasmi kwa mwanaume`, ipa: `pahn`},{pl: `pani`, sw: `bibi / wewe rasmi kwa mwanamke`, ipa: `PAH-nee`},{pl: `imię`, sw: `jina`, ipa: `EE-myeh`},{pl: `nazywam się`, sw: `ninaitwa`, ipa: `nah-ZIH-vam shyeh`},{pl: `jestem`, sw: `mimi ni / niko`, ipa: `YES-tem`},{pl: `miło`, sw: `vizuri / furaha`, ipa: `MEE-woh`},{pl: `bardzo`, sw: `sana`, ipa: `BAR-dzoh`},{pl: `skąd`, sw: `kutoka wapi`, ipa: `skont`}], phrases: [{pl: `Jak masz na imię?`, sw: `Unaitwa nani?`, ipa: `yahk mash nah EE-myeh`},{pl: `Mam na imię Asha.`, sw: `Ninaitwa Asha.`, ipa: `mam nah EE-myeh AH-shah`},{pl: `Jak się pan nazywa?`, sw: `Bwana anaitwa nani?`, ipa: `yahk shyeh pahn nah-ZIH-vah`},{pl: `Jak się pani nazywa?`, sw: `Bibi anaitwa nani?`, ipa: `yahk shyeh PAH-nee nah-ZIH-vah`},{pl: `Miło mi.`, sw: `Nimefurahi kukutana nawe.`, ipa: `MEE-woh mee`},{pl: `Jestem z Tanzanii.`, sw: `Ninatoka Tanzania.`, ipa: `YES-tem z tan-ZAH-nee`}], grammar: `Kipolishi kina namna rasmi na isiyo rasmi ya kuongea. “Ty” ni kwa marafiki au watu wa karibu, lakini “pan” na “pani” hutumika kwa heshima. Ukiwa msafiri, kutumia “pan” au “pani” mara nyingi huonekana kuwa adabu.`, practice: [`Jitambulishe kwa kutumia “Mam na imię...”`,`Uliza jina la mtu kwa namna isiyo rasmi.`,`Uliza jina la mtu kwa namna rasmi kwa mwanamke.`,`Sema unatoka Tanzania, Kenya, au Uganda kwa Kipolishi.`,`Fanya mazungumzo mafupi ya mistari minne kuhusu majina.`]},{day: 3, title: `Maneno ya lazima kwa msafiri`, title_native: `Niezbędne słowa podróżnika`, focus: `Leo unajenga kifurushi cha maneno ya kuishi ukiwa Łódź, Wrocław au Lublin. Maneno haya yatakusaidia unapotaka msaada, unapoomba kitu, au unapokosea.`, vocab: [{pl: `pomoc`, sw: `msaada`, ipa: `POH-mots`},{pl: `woda`, sw: `maji`, ipa: `VOH-dah`},{pl: `toaleta`, sw: `choo`, ipa: `toh-ah-LEH-tah`},{pl: `telefon`, sw: `simu`, ipa: `teh-LEH-fon`},{pl: `hotel`, sw: `hoteli`, ipa: `HOH-tel`},{pl: `ulica`, sw: `mtaa`, ipa: `oo-LEE-tsah`},{pl: `mapa`, sw: `ramani`, ipa: `MAH-pah`},{pl: `bilet`, sw: `tiketi`, ipa: `BEE-let`},{pl: `problem`, sw: `tatizo`, ipa: `PROH-blem`},{pl: `teraz`, sw: `sasa`, ipa: `TEH-ras`}], phrases: [{pl: `Potrzebuję pomocy.`, sw: `Ninahitaji msaada.`, ipa: `poh-tsheh-BOO-yeh POH-moh-tsih`},{pl: `Gdzie jest toaleta?`, sw: `Choo kiko wapi?`, ipa: `gjeh yest toh-ah-LEH-tah`},{pl: `Poproszę wodę.`, sw: `Naomba maji.`, ipa: `poh-PROH-sheh VOH-deh`},{pl: `Mam problem.`, sw: `Nina tatizo.`, ipa: `mam PROH-blem`},{pl: `Nie mówię dobrze po polsku.`, sw: `Sizungumzi Kipolishi vizuri.`, ipa: `nyeh MOO-vyeh DOH-bzheh poh POL-skoo`},{pl: `Czy mówi pan po angielsku?`, sw: `Je, bwana anaongea Kiingereza?`, ipa: `chih MOO-vee pahn poh an-GYEL-skoo`}], grammar: `“Nahitaji” mara nyingi hutafsiriwa kama “potrzebuję,” na neno linalofuata huwa kitu unachohitaji. “Poproszę” ni neno muhimu sana kwenye maduka na migahawa; lina maana ya “naomba” kwa heshima. Litumie unapoweka oda au unaponunua kitu.`, practice: [`Sema “Ninahitaji msaada” kwa Kipolishi.`,`Uliza choo kiko wapi.`,`Omba maji kwa heshima.`,`Sema husemi Kipolishi vizuri.`,`Andika orodha ya vitu vitatu unavyoweza kuomba kwa “Poproszę...”`]},{day: 4, title: `Nambari na bei ndogo`, title_native: `Liczby i małe ceny`, focus: `Ukiwa sokoni Kraków au kwenye kioski Warsaw, utahitaji kuelewa bei na kiasi. Leo unajifunza nambari za msingi na jinsi ya kuuliza gharama.`, vocab: [{pl: `jeden`, sw: `moja`, ipa: `YEH-den`},{pl: `dwa`, sw: `mbili`, ipa: `dvah`},{pl: `trzy`, sw: `tatu`, ipa: `tshih`},{pl: `cztery`, sw: `nne`, ipa: `CHTEH-ri`},{pl: `pięć`, sw: `tano`, ipa: `pyench`},{pl: `sześć`, sw: `sita`, ipa: `sheshch`},{pl: `siedem`, sw: `saba`, ipa: `SHYEH-dem`},{pl: `osiem`, sw: `nane`, ipa: `OH-shyem`},{pl: `dziewięć`, sw: `tisa`, ipa: `JYEH-vyench`},{pl: `dziesięć`, sw: `kumi`, ipa: `JYEH-shyench`}], phrases: [{pl: `Ile to kosztuje?`, sw: `Hii inagharimu kiasi gani?`, ipa: `EE-leh toh kosh-TOO-yeh`},{pl: `To kosztuje pięć złotych.`, sw: `Hii inagharimu zloty tano.`, ipa: `toh kosh-TOO-yeh pyench ZWOH-tih`},{pl: `Poproszę dwa bilety.`, sw: `Naomba tiketi mbili.`, ipa: `poh-PROH-sheh dvah BEE-leh-tih`},{pl: `Mam dziesięć złotych.`, sw: `Nina zloty kumi.`, ipa: `mam JYEH-shyench ZWOH-tih`},{pl: `Czy to jest tanie?`, sw: `Je, hii ni bei nafuu?`, ipa: `chih toh yest TAH-nyeh`},{pl: `To jest drogie.`, sw: `Hii ni ghali.`, ipa: `toh yest DROH-gyeh`}], grammar: `Sarafu ya Poland ni “złoty.” Baada ya nambari, umbo la neno linaweza kubadilika, lakini kwa msafiri ni muhimu kwanza kuelewa “złoty” na “złotych.” Wauzaji watakuelewa hata ukitumia miundo rahisi.`, practice: [`Hesabu kutoka moja hadi kumi kwa Kipolishi.`,`Uliza bei ya kitu.`,`Omba tiketi mbili.`,`Sema una zloty kumi.`,`Sikiliza au sema nambari “pięć,” “sześć,” na “dziesięć” polepole.`]},{day: 5, title: `Siku, muda na miadi rahisi`, title_native: `Dni, czas i proste spotkania`, focus: `Leo unajifunza kupanga muda ukiwa Poland, hasa kwa ziara, treni au kukutana na mtu. Hii ni muhimu unapopanga siku yako huko Warsaw au Gdańsk.`, vocab: [{pl: `dzisiaj`, sw: `leo`, ipa: `JEE-shai`},{pl: `jutro`, sw: `kesho`, ipa: `YOO-troh`},{pl: `wczoraj`, sw: `jana`, ipa: `FCHOH-rai`},{pl: `rano`, sw: `asubuhi`, ipa: `RAH-noh`},{pl: `wieczorem`, sw: `jioni`, ipa: `vyeh-CHOH-rem`},{pl: `dzień`, sw: `siku`, ipa: `jen`},{pl: `tydzień`, sw: `wiki`, ipa: `TIH-jen`},{pl: `godzina`, sw: `saa`, ipa: `goh-JEE-nah`},{pl: `teraz`, sw: `sasa`, ipa: `TEH-ras`},{pl: `później`, sw: `baadaye`, ipa: `POOZH-nyey`}], phrases: [{pl: `Która godzina?`, sw: `Ni saa ngapi?`, ipa: `KTOO-rah goh-JEE-nah`},{pl: `Jest ósma.`, sw: `Ni saa mbili asubuhi / saa nane kulingana na mfumo.`, ipa: `yest OOS-mah`},{pl: `Dzisiaj idę do muzeum.`, sw: `Leo ninaenda makumbusho.`, ipa: `JEE-shai EE-deh doh moo-ZEH-oom`},{pl: `Jutro mam pociąg.`, sw: `Kesho nina treni.`, ipa: `YOO-troh mam POH-chonk`},{pl: `Do zobaczenia później.`, sw: `Tutaonana baadaye.`, ipa: `doh zoh-bah-CHEH-nyah POOZH-nyey`},{pl: `Mam spotkanie rano.`, sw: `Nina miadi asubuhi.`, ipa: `mam spot-KAH-nyeh RAH-noh`}], grammar: `Kipolishi hutumia “mam” kusema “nina,” kama “Mam pociąg” kwa maana ya “nina treni.” Kwa muda, “godzina” ni saa kama wakati, si kifaa cha saa. Ukiwa unaelewa ratiba, zingatia nambari na maneno kama “dzisiaj,” “jutro,” na “rano.”`, practice: [`Sema leo, kesho na jana kwa Kipolishi.`,`Uliza “Ni saa ngapi?”`,`Sema una treni kesho.`,`Tunga sentensi kuhusu makumbusho leo.`,`Sema “Tutaonana baadaye” kwa sauti mara tatu.`]},{day: 6, title: `Uwanja wa ndege na kuwasili`, title_native: `Lotnisko i przylot`, focus: `Sasa unawasili kwenye uwanja wa ndege wa Chopin Warsaw au Kraków-Balice. Utajifunza maneno ya mizigo, pasipoti na njia ya kutoka.`, vocab: [{pl: `lotnisko`, sw: `uwanja wa ndege`, ipa: `lot-NEE-skoh`},{pl: `paszport`, sw: `pasipoti`, ipa: `PASH-port`},{pl: `bagaż`, sw: `mzigo`, ipa: `BAH-gash`},{pl: `walizka`, sw: `sanduku`, ipa: `vah-LEES-kah`},{pl: `bramka`, sw: `geti`, ipa: `BRAM-kah`},{pl: `przylot`, sw: `kuwasili kwa ndege`, ipa: `PSHIH-lot`},{pl: `odlot`, sw: `kuondoka kwa ndege`, ipa: `OD-lot`},{pl: `kontrola`, sw: `ukaguzi`, ipa: `kon-TROH-lah`},{pl: `wyjście`, sw: `kutoka`, ipa: `VIH-shchyeh`},{pl: `taxi`, sw: `teksi`, ipa: `TAK-see`}], phrases: [{pl: `Gdzie jest wyjście?`, sw: `Njia ya kutoka iko wapi?`, ipa: `gjeh yest VIH-shchyeh`},{pl: `To jest mój paszport.`, sw: `Hii ni pasipoti yangu.`, ipa: `toh yest mooy PASH-port`},{pl: `Nie mam bagażu.`, sw: `Sina mzigo.`, ipa: `nyeh mam BAH-gah-zhoo`},{pl: `Mam jedną walizkę.`, sw: `Nina sanduku moja.`, ipa: `mam YED-nom vah-LEES-keh`},{pl: `Gdzie jest postój taxi?`, sw: `Kituo cha teksi kiko wapi?`, ipa: `gjeh yest POS-tooy TAK-see`},{pl: `Potrzebuję informacji.`, sw: `Ninahitaji taarifa.`, ipa: `poh-tsheh-BOO-yeh in-for-MAH-tsyee`}], grammar: `“Nina” ni “mam,” na “sina” ni “nie mam.” Katika Kipolishi, “mój” ni “yangu” kwa kitu cha jinsia ya kiume kama “paszport.” Usihofu sana kuhusu jinsia mwanzoni; maneno muhimu yatakusaidia kueleweka.`, practice: [`Sema “Hii ni pasipoti yangu.”`,`Uliza njia ya kutoka uwanjani.`,`Sema una sanduku moja.`,`Uliza kituo cha teksi kiko wapi.`,`Andika maneno matano yanayohusiana na uwanja wa ndege.`]},{day: 7, title: `Hoteli na kuingia chumbani`, title_native: `Hotel i zameldowanie`, focus: `Ukiwa hoteli Warsaw, Wrocław au Zakopane, utahitaji kuingia, kuuliza kuhusu chumba na Wi-Fi. Leo unajifunza mazungumzo muhimu ya mapokezi.`, vocab: [{pl: `hotel`, sw: `hoteli`, ipa: `HOH-tel`},{pl: `recepcja`, sw: `mapokezi`, ipa: `reh-TSEP-tsyah`},{pl: `pokój`, sw: `chumba`, ipa: `POH-kooy`},{pl: `rezerwacja`, sw: `nafasi iliyohifadhiwa`, ipa: `reh-zer-VAH-tsyah`},{pl: `klucz`, sw: `ufunguo`, ipa: `klooch`},{pl: `winda`, sw: `lifti`, ipa: `VEEN-dah`},{pl: `łóżko`, sw: `kitanda`, ipa: `WOOSH-koh`},{pl: `łazienka`, sw: `bafu / choo`, ipa: `wah-ZYEN-kah`},{pl: `śniadanie`, sw: `kifungua kinywa`, ipa: `shnya-DAH-nyeh`},{pl: `internet`, sw: `intaneti`, ipa: `in-TER-net`}], phrases: [{pl: `Mam rezerwację.`, sw: `Nina nafasi iliyohifadhiwa.`, ipa: `mam reh-zer-VAH-tsyeh`},{pl: `Na nazwisko Cannon.`, sw: `Kwa jina Cannon.`, ipa: `nah naz-VEES-koh KAN-on`},{pl: `Poproszę klucz.`, sw: `Naomba ufunguo.`, ipa: `poh-PROH-sheh klooch`},{pl: `Gdzie jest winda?`, sw: `Lifti iko wapi?`, ipa: `gjeh yest VEEN-dah`},{pl: `Czy jest śniadanie?`, sw: `Je, kuna kifungua kinywa?`, ipa: `chih yest shnya-DAH-nyeh`},{pl: `Jakie jest hasło do Wi-Fi?`, sw: `Nenosiri la Wi-Fi ni nini?`, ipa: `YAH-kyeh yest HAS-woh doh VAI-fai`}], grammar: `“Czy” huanzisha swali la ndiyo/hapana, kama “Czy jest śniadanie?” Unaweza kutumia muundo huu kwa vitu vingi: “Czy jest Wi-Fi?” au “Czy jest parking?” Ni njia rahisi ya kuuliza huduma.`, practice: [`Sema una nafasi iliyohifadhiwa.`,`Uliza kama kuna kifungua kinywa.`,`Uliza nenosiri la Wi-Fi.`,`Omba ufunguo kwa heshima.`,`Tunga mazungumzo mafupi ya mapokezi ya hoteli.`]},{day: 8, title: `Mwelekeo mjini`, title_native: `Kierunki w mieście`, focus: `Leo unatembea kwenye Old Town ya Kraków au Warsaw na unahitaji kuuliza njia. Utajifunza maneno ya kushoto, kulia na moja kwa moja.`, vocab: [{pl: `gdzie`, sw: `wapi`, ipa: `gjeh`},{pl: `tutaj`, sw: `hapa`, ipa: `TOO-tai`},{pl: `tam`, sw: `pale / huko`, ipa: `tam`},{pl: `prosto`, sw: `moja kwa moja`, ipa: `PROS-toh`},{pl: `w lewo`, sw: `kushoto`, ipa: `v LEH-voh`},{pl: `w prawo`, sw: `kulia`, ipa: `v PRAH-voh`},{pl: `ulica`, sw: `mtaa`, ipa: `oo-LEE-tsah`},{pl: `rynek`, sw: `soko kuu / uwanja wa mji`, ipa: `RIH-nek`},{pl: `most`, sw: `daraja`, ipa: `most`},{pl: `blisko`, sw: `karibu`, ipa: `BLEES-koh`}], phrases: [{pl: `Gdzie jest rynek?`, sw: `Soko kuu liko wapi?`, ipa: `gjeh yest RIH-nek`},{pl: `Proszę iść prosto.`, sw: `Tafadhali nenda moja kwa moja.`, ipa: `PROH-sheh eeshch PROS-toh`},{pl: `Potem w lewo.`, sw: `Kisha kushoto.`, ipa: `POH-tem v LEH-voh`},{pl: `To jest blisko.`, sw: `Hapo ni karibu.`, ipa: `toh yest BLEES-koh`},{pl: `Czy to daleko?`, sw: `Je, ni mbali?`, ipa: `chih toh dah-LEH-koh`},{pl: `Szukam ulicy Długiej.`, sw: `Natafuta Mtaa wa Długa.`, ipa: `SHOO-kam oo-LEE-tsih DWOO-gyey`}], grammar: `Katika maelekezo, “iść” ni “kwenda kwa miguu.” Unaweza kusikia “proszę iść,” ambayo ni namna ya heshima ya kusema “tafadhali nenda.” Majina ya mitaa mara nyingi hubadilika kidogo baada ya “ulicy,” lakini kutaja jina lenyewe bado hueleweka.`, practice: [`Uliza soko kuu liko wapi.`,`Sema “moja kwa moja, kisha kulia.”`,`Uliza kama sehemu ni mbali.`,`Taja mtaa unaoutafuta kwa kutumia “Szukam ulicy...”`,`Chora ramani ndogo na ujielekeze kwa Kipolishi.`]},{day: 9, title: `Usafiri wa umma`, title_native: `Transport publiczny`, focus: `Ukiwa Warsaw, Kraków au Gdańsk, tramu na mabasi ni muhimu. Leo unajifunza kununua tiketi na kuuliza kituo sahihi.`, vocab: [{pl: `autobus`, sw: `basi`, ipa: `ow-TOH-boos`},{pl: `tramwaj`, sw: `tramu`, ipa: `TRAM-vai`},{pl: `metro`, sw: `metro`, ipa: `MEH-troh`},{pl: `pociąg`, sw: `treni`, ipa: `POH-chonk`},{pl: `przystanek`, sw: `kituo`, ipa: `pshi-STAH-nek`},{pl: `dworzec`, sw: `stesheni kuu`, ipa: `DVOH-zhets`},{pl: `bilet`, sw: `tiketi`, ipa: `BEE-let`},{pl: `kontroler`, sw: `mkaguzi wa tiketi`, ipa: `kon-TROH-ler`},{pl: `linia`, sw: `laini / namba ya njia`, ipa: `LEE-nyah`},{pl: `stacja`, sw: `kituo cha treni / metro`, ipa: `STAH-tsyah`}], phrases: [{pl: `Poproszę bilet jednorazowy.`, sw: `Naomba tiketi ya safari moja.`, ipa: `poh-PROH-sheh BEE-let yed-noh-rah-ZOH-vih`},{pl: `Gdzie jest przystanek autobusowy?`, sw: `Kituo cha basi kiko wapi?`, ipa: `gjeh yest pshi-STAH-nek ow-toh-boo-SOH-vih`},{pl: `Czy ten tramwaj jedzie do centrum?`, sw: `Je, tramu hii inaenda katikati ya mji?`, ipa: `chih ten TRAM-vai YED-zheh doh TSEN-troom`},{pl: `Muszę skasować bilet.`, sw: `Lazima nihakikishe tiketi kwenye mashine.`, ipa: `MOO-sheh skah-SOH-vach BEE-let`},{pl: `Która to linia?`, sw: `Hii ni laini gani?`, ipa: `KTOO-rah toh LEE-nyah`},{pl: `Wysiadam tutaj.`, sw: `Ninashuka hapa.`, ipa: `vih-SYAH-dam TOO-tai`}], grammar: `“Ten” ina maana ya “huyu/hii” kwa nomino nyingi za jinsia ya kiume, kama “ten tramwaj.” Kwa usafiri, kitenzi “jedzie” kinamaanisha “inaenda” kwa gari, basi, tramu au treni. “Czy ten tramwaj jedzie do centrum?” ni swali muhimu sana.`, practice: [`Omba tiketi ya safari moja.`,`Uliza kama tramu inaenda katikati ya mji.`,`Sema unashuka hapa.`,`Uliza kituo cha basi kiko wapi.`,`Taja aina tatu za usafiri wa umma kwa Kipolishi.`]},{day: 10, title: `Kwenye mkahawa`, title_native: `W kawiarni`, focus: `Leo unaingia kwenye mkahawa wa Kraków au Poznań na kuagiza kahawa, chai au keki. Utajifunza kutumia “poproszę” kwa oda rahisi.`, vocab: [{pl: `kawa`, sw: `kahawa`, ipa: `KAH-vah`},{pl: `herbata`, sw: `chai`, ipa: `her-BAH-tah`},{pl: `mleko`, sw: `maziwa`, ipa: `MLEH-koh`},{pl: `cukier`, sw: `sukari`, ipa: `TSOO-kyer`},{pl: `ciasto`, sw: `keki`, ipa: `CHAS-toh`},{pl: `kanapka`, sw: `sandwichi`, ipa: `kah-NAP-kah`},{pl: `filiżanka`, sw: `kikombe`, ipa: `fee-lee-ZHAN-kah`},{pl: `łyżeczka`, sw: `kijiko kidogo`, ipa: `wih-ZHECH-kah`},{pl: `rachunek`, sw: `bili`, ipa: `rah-HOO-nek`},{pl: `stolik`, sw: `meza`, ipa: `STOH-leek`}], phrases: [{pl: `Poproszę kawę.`, sw: `Naomba kahawa.`, ipa: `poh-PROH-sheh KAH-veh`},{pl: `Poproszę herbatę z cytryną.`, sw: `Naomba chai yenye limau.`, ipa: `poh-PROH-sheh her-BAH-teh z tsih-TRIH-nom`},{pl: `Czy jest mleko?`, sw: `Je, kuna maziwa?`, ipa: `chih yest MLEH-koh`},{pl: `Bez cukru, proszę.`, sw: `Bila sukari, tafadhali.`, ipa: `bez TSOO-kroo PROH-sheh`},{pl: `Poproszę ciasto.`, sw: `Naomba keki.`, ipa: `poh-PROH-sheh CHAS-toh`},{pl: `Poproszę rachunek.`, sw: `Naomba bili.`, ipa: `poh-PROH-sheh rah-HOO-nek`}], grammar: `“Z” maana yake ni “na” au “yenye,” kama “herbata z cytryną.” “Bez” maana yake ni “bila,” kama “bez cukru.” Maneno haya mawili yatakusaidia sana unapobadilisha oda yako.`, practice: [`Agiza kahawa kwa Kipolishi.`,`Agiza chai yenye limau.`,`Sema “bila sukari, tafadhali.”`,`Omba bili.`,`Tunga oda moja kamili ya mkahawa.`]},{day: 11, title: `Chakula cha Kipolishi`, title_native: `Polskie jedzenie`, focus: `Ukiwa Poland, utakutana na pierogi, supu na vyakula vya kienyeji. Leo unajifunza kuuliza kuhusu chakula na kuagiza sahani rahisi.`, vocab: [{pl: `jedzenie`, sw: `chakula`, ipa: `yed-ZEH-nyeh`},{pl: `zupa`, sw: `supu`, ipa: `ZOO-pah`},{pl: `pierogi`, sw: `pierogi / maandazi ya kujazwa`, ipa: `pyeh-ROH-gee`},{pl: `chleb`, sw: `mkate`, ipa: `hlep`},{pl: `masło`, sw: `siagi`, ipa: `MAH-swoh`},{pl: `ser`, sw: `jibini`, ipa: `ser`},{pl: `mięso`, sw: `nyama`, ipa: `MYEN-soh`},{pl: `ryba`, sw: `samaki`, ipa: `RIH-bah`},{pl: `warzywa`, sw: `mboga`, ipa: `vah-ZHIH-vah`},{pl: `ziemniaki`, sw: `viazi`, ipa: `zhyem-NYAH-kee`}], phrases: [{pl: `Co pan poleca?`, sw: `Bwana anapendekeza nini?`, ipa: `tsoh pahn poh-LEH-tsah`},{pl: `Co pani poleca?`, sw: `Bibi anapendekeza nini?`, ipa: `tsoh PAH-nee poh-LEH-tsah`},{pl: `Poproszę pierogi.`, sw: `Naomba pierogi.`, ipa: `poh-PROH-sheh pyeh-ROH-gee`},{pl: `Czy to jest z mięsem?`, sw: `Je, hii ina nyama?`, ipa: `chih toh yest z MYEN-sem`},{pl: `Jestem wegetarianinem.`, sw: `Mimi ni mla mboga.`, ipa: `YES-tem veh-geh-tah-ryah-NEE-nem`},{pl: `To jest bardzo dobre.`, sw: `Hii ni tamu sana.`, ipa: `toh yest BAR-dzoh DOH-breh`}], grammar: `“Co” maana yake ni “nini.” Unaweza kuuliza “Co pan poleca?” kwa mhudumu mwanaume au “Co pani poleca?” kwa mhudumu mwanamke. Hii ni njia ya asili ya kupata pendekezo kwenye mgahawa.`, practice: [`Uliza mhudumu anapendekeza nini.`,`Agiza pierogi.`,`Uliza kama sahani ina nyama.`,`Sema wewe ni mla mboga.`,`Sema chakula ni kizuri sana.`]},{day: 12, title: `Mkahawa wa jioni na oda kamili`, title_native: `Restauracja i pełne zamówienie`, focus: `Leo unaingia mgahawani Wrocław au Toruń kwa chakula cha jioni. Utajifunza kuomba meza, menyu, sahani kuu na bili.`, vocab: [{pl: `restauracja`, sw: `mgahawa`, ipa: `res-tow-RAH-tsyah`},{pl: `menu`, sw: `menyu`, ipa: `MEH-noo`},{pl: `kelner`, sw: `mhudumu mwanaume`, ipa: `KEL-ner`},{pl: `kelnerka`, sw: `mhudumu mwanamke`, ipa: `kel-NER-kah`},{pl: `danie`, sw: `sahani / mlo`, ipa: `DAH-nyeh`},{pl: `przystawka`, sw: `kitangulizi`, ipa: `pshi-STAF-kah`},{pl: `deser`, sw: `dessert`, ipa: `DEH-ser`},{pl: `napój`, sw: `kinywaji`, ipa: `NAH-pooy`},{pl: `widelec`, sw: `uma`, ipa: `vee-DEH-lets`},{pl: `nóż`, sw: `kisu`, ipa: `noosh`}], phrases: [{pl: `Stolik dla dwóch osób, proszę.`, sw: `Meza ya watu wawili, tafadhali.`, ipa: `STOH-leek dla dvooh OH-soob PROH-sheh`},{pl: `Poproszę menu.`, sw: `Naomba menyu.`, ipa: `poh-PROH-sheh MEH-noo`},{pl: `Czy mogę zamówić?`, sw: `Naweza kuagiza?`, ipa: `chih MOH-geh zah-MOO-veech`},{pl: `Poproszę danie dnia.`, sw: `Naomba mlo wa siku.`, ipa: `poh-PROH-sheh DAH-nyeh dnyah`},{pl: `Jeszcze wodę, proszę.`, sw: `Maji pia, tafadhali.`, ipa: `YESH-cheh VOH-deh PROH-sheh`},{pl: `Czy można płacić kartą?`, sw: `Je, naweza kulipa kwa kadi?`, ipa: `chih MOZH-nah PWAH-cheech KAR-tom`}], grammar: `“Dla” maana yake ni “kwa ajili ya,” kama “dla dwóch osób” kwa “kwa watu wawili.” “Czy można...” ni njia ya heshima ya kuuliza kama kitu kinawezekana. Hii ni muhimu kwenye migahawa, makumbusho na usafiri.`, practice: [`Omba meza ya watu wawili.`,`Omba menyu.`,`Uliza kama unaweza kuagiza.`,`Omba mlo wa siku.`,`Uliza kama unaweza kulipa kwa kadi.`]},{day: 13, title: `Kununua sokoni`, title_native: `Zakupy na targu`, focus: `Masoko ya Poland yana matunda, maua, mikate na bidhaa za kienyeji. Leo unajifunza kuuliza bei, kuchagua kiasi na kusema unachotaka.`, vocab: [{pl: `targ`, sw: `soko`, ipa: `tark`},{pl: `sklep`, sw: `duka`, ipa: `sklep`},{pl: `jabłko`, sw: `tufaha`, ipa: `YAP-koh`},{pl: `banan`, sw: `ndizi`, ipa: `BAH-nan`},{pl: `pomidor`, sw: `nyanya`, ipa: `poh-MEE-dor`},{pl: `ziemniak`, sw: `kiazi`, ipa: `ZHYEM-nyak`},{pl: `kilo`, sw: `kilo`, ipa: `KEE-loh`},{pl: `torba`, sw: `mfuko`, ipa: `TOR-bah`},{pl: `gotówka`, sw: `pesa taslimu`, ipa: `goh-TOOF-kah`},{pl: `karta`, sw: `kadi`, ipa: `KAR-tah`}], phrases: [{pl: `Ile kosztuje kilo jabłek?`, sw: `Kilo ya matufaha ni bei gani?`, ipa: `EE-leh kosh-TOO-yeh KEE-loh YAP-wek`},{pl: `Poproszę pół kilo pomidorów.`, sw: `Naomba nusu kilo ya nyanya.`, ipa: `poh-PROH-sheh pool KEE-loh poh-mee-DOH-roof`},{pl: `Czy mogę zapłacić kartą?`, sw: `Naweza kulipa kwa kadi?`, ipa: `chih MOH-geh zah-PWAH-cheech KAR-tom`},{pl: `Nie potrzebuję torby.`, sw: `Sihitaji mfuko.`, ipa: `nyeh poh-tsheh-BOO-yeh TOR-bih`},{pl: `To wszystko, dziękuję.`, sw: `Ni hayo tu, asante.`, ipa: `toh FSHIH-stkoh jen-KOO-yeh`},{pl: `Poproszę jeszcze banany.`, sw: `Naomba ndizi pia.`, ipa: `poh-PROH-sheh YESH-cheh bah-NAH-nih`}], grammar: `“Jeszcze” inaweza kumaanisha “bado” au “pia/zaidi” kwenye oda. “Poproszę jeszcze...” ni njia nzuri ya kuongeza kitu. Sokoni, unaweza kutumia misemo mifupi; adabu na tabasamu husaidia sana.`, practice: [`Uliza bei ya kilo ya matufaha.`,`Omba nusu kilo ya nyanya.`,`Sema huhitaji mfuko.`,`Uliza kama unaweza kulipa kwa kadi.`,`Tunga oda ya sokoni yenye vitu vitatu.`]},{day: 14, title: `Nguo na zawadi`, title_native: `Ubrania i prezenty`, focus: `Leo unatembelea duka la nguo au zawadi huko Zakopane au Gdańsk. Utajifunza kuuliza rangi, ukubwa na kujaribu kitu.`, vocab: [{pl: `ubranie`, sw: `nguo`, ipa: `oo-BRAH-nyeh`},{pl: `koszula`, sw: `shati`, ipa: `koh-SHOO-lah`},{pl: `spodnie`, sw: `suruali`, ipa: `SPOD-nyeh`},{pl: `sukienka`, sw: `gauni`, ipa: `soo-KYEN-kah`},{pl: `buty`, sw: `viatu`, ipa: `BOO-tih`},{pl: `rozmiar`, sw: `saizi`, ipa: `ROZ-myar`},{pl: `kolor`, sw: `rangi`, ipa: `KOH-lor`},{pl: `prezent`, sw: `zawadi`, ipa: `PREH-zent`},{pl: `pamiątka`, sw: `ukumbusho / souvenir`, ipa: `pah-MYONT-kah`},{pl: `paragon`, sw: `risiti`, ipa: `pah-RAH-gon`}], phrases: [{pl: `Czy mogę to przymierzyć?`, sw: `Naweza kujaribu hii?`, ipa: `chih MOH-geh toh pshi-MYEH-zhich`},{pl: `Jaki to rozmiar?`, sw: `Hii ni saizi gani?`, ipa: `YAH-kee toh ROZ-myar`},{pl: `Czy jest większy rozmiar?`, sw: `Je, kuna saizi kubwa zaidi?`, ipa: `chih yest VYENK-shih ROZ-myar`},{pl: `Czy jest inny kolor?`, sw: `Je, kuna rangi nyingine?`, ipa: `chih yest EEN-nih KOH-lor`},{pl: `Szukam prezentu.`, sw: `Natafuta zawadi.`, ipa: `SHOO-kam PREH-zen-too`},{pl: `Poproszę paragon.`, sw: `Naomba risiti.`, ipa: `poh-PROH-sheh pah-RAH-gon`}], grammar: `“Jaki” ni “gani/aina gani” kwa nomino nyingi za kiume, kama “rozmiar.” “Inny” maana yake ni “nyingine,” na “większy” ni “kubwa zaidi.” Haya ni maneno muhimu unapochagua bidhaa.`, practice: [`Uliza kama unaweza kujaribu nguo.`,`Uliza saizi ya kitu.`,`Omba saizi kubwa zaidi.`,`Uliza kama kuna rangi nyingine.`,`Sema unatafuta zawadi.`]},{day: 15, title: `Afya na duka la dawa`, title_native: `Zdrowie i apteka`, focus: `Ukiwa msafiri unaweza kuhitaji dawa ya maumivu, baridi au msaada wa haraka. Leo unajifunza maneno ya apteka na kueleza dalili rahisi.`, vocab: [{pl: `apteka`, sw: `duka la dawa`, ipa: `ap-TEH-kah`},{pl: `lekarz`, sw: `daktari`, ipa: `LEH-kash`},{pl: `lek`, sw: `dawa`, ipa: `lek`},{pl: `ból`, sw: `maumivu`, ipa: `bool`},{pl: `głowa`, sw: `kichwa`, ipa: `GWOH-vah`},{pl: `brzuch`, sw: `tumbo`, ipa: `bzhook`},{pl: `gorączka`, sw: `homa`, ipa: `goh-RONCH-kah`},{pl: `kaszel`, sw: `kikohozi`, ipa: `KAH-shel`},{pl: `alergia`, sw: `mzio`, ipa: `ah-LER-gyah`},{pl: `recepta`, sw: `cheti cha dawa`, ipa: `reh-TSEP-tah`}], phrases: [{pl: `Gdzie jest apteka?`, sw: `Duka la dawa liko wapi?`, ipa: `gjeh yest ap-TEH-kah`},{pl: `Boli mnie głowa.`, sw: `Kichwa kinaniuma.`, ipa: `BOH-lee mnyeh GWOH-vah`},{pl: `Boli mnie brzuch.`, sw: `Tumbo linaniuma.`, ipa: `BOH-lee mnyeh bzhook`},{pl: `Mam gorączkę.`, sw: `Nina homa.`, ipa: `mam goh-RONCH-keh`},{pl: `Potrzebuję lekarza.`, sw: `Ninahitaji daktari.`, ipa: `poh-tsheh-BOO-yeh LEH-kah-zhah`},{pl: `Mam alergię.`, sw: `Nina mzio.`, ipa: `mam ah-LER-gyeh`}], grammar: `Kwa maumivu, Kipolishi hutumia muundo “Boli mnie...” maana yake “kinaniuma.” Unaweza kusema “Boli mnie głowa” au “Boli mnie brzuch.” Kwa hali ya dharura, sema kwa uwazi na tumia ishara kama inahitajika.`, practice: [`Uliza duka la dawa liko wapi.`,`Sema kichwa kinakuuma.`,`Sema una homa.`,`Sema unahitaji daktari.`,`Andika dalili tatu kwa Kipolishi.`]},{day: 16, title: `Dharura na usalama`, title_native: `Nagłe sytuacje i bezpieczeństwo`, focus: `Leo unajifunza maneno ya dharura ukiwa popote Poland. Haya si maneno ya kutumia kila siku, lakini ni muhimu sana kwa usalama wa msafiri.`, vocab: [{pl: `policja`, sw: `polisi`, ipa: `poh-LEETS-yah`},{pl: `pogotowie`, sw: `ambulansi / huduma ya dharura`, ipa: `poh-goh-TOH-vyeh`},{pl: `straż pożarna`, sw: `zimamoto`, ipa: `strash poh-ZHAR-nah`},{pl: `pomocy`, sw: `msaada!`, ipa: `poh-MOH-tsih`},{pl: `wypadek`, sw: `ajali`, ipa: `vih-PAH-dek`},{pl: `kradzież`, sw: `wizi`, ipa: `KRAH-jyesh`},{pl: `zgubiłem`, sw: `nimepoteza, mwanaume akisema`, ipa: `zgoo-BEE-wem`},{pl: `zgubiłam`, sw: `nimepoteza, mwanamke akisema`, ipa: `zgoo-BEE-wam`},{pl: `dokumenty`, sw: `nyaraka`, ipa: `doh-koo-MEN-tih`},{pl: `bezpiecznie`, sw: `salama`, ipa: `bez-PYECH-nyeh`}], phrases: [{pl: `Pomocy!`, sw: `Msaada!`, ipa: `poh-MOH-tsih`},{pl: `Proszę wezwać policję.`, sw: `Tafadhali ita polisi.`, ipa: `PROH-sheh VEZ-vach poh-LEETS-yeh`},{pl: `Był wypadek.`, sw: `Kulikuwa na ajali.`, ipa: `biw vih-PAH-dek`},{pl: `Zgubiłem paszport.`, sw: `Nimepoteza pasipoti, mwanaume akisema.`, ipa: `zgoo-BEE-wem PASH-port`},{pl: `Zgubiłam telefon.`, sw: `Nimepoteza simu, mwanamke akisema.`, ipa: `zgoo-BEE-wam teh-LEH-fon`},{pl: `Czy tutaj jest bezpiecznie?`, sw: `Je, hapa ni salama?`, ipa: `chih TOO-tai yest bez-PYECH-nyeh`}], grammar: `Baadhi ya vitenzi hubadilika kulingana na jinsia ya mzungumzaji. “Zgubiłem” hutumiwa na mwanaume, “zgubiłam” na mwanamke. Hata ukichanganya, watu wataelewa, lakini kujua tofauti husaidia.`, practice: [`Sema “Msaada!” kwa Kipolishi.`,`Omba mtu aite polisi.`,`Sema umepoteza pasipoti.`,`Uliza kama sehemu ni salama.`,`Fanya mazoezi ya kusema namba ya dharura ya Ulaya: 112.`]},{day: 17, title: `Hali ya hewa na mipango`, title_native: `Pogoda i plany`, focus: `Hali ya hewa Poland hubadilika, hasa kati ya majira ya baridi na kiangazi. Leo unajifunza kuzungumzia baridi, mvua na mipango ya siku.`, vocab: [{pl: `pogoda`, sw: `hali ya hewa`, ipa: `poh-GOH-dah`},{pl: `zimno`, sw: `baridi`, ipa: `ZHEEM-noh`},{pl: `ciepło`, sw: `joto / vuguvugu`, ipa: `CHPYEH-woh`},{pl: `gorąco`, sw: `joto kali`, ipa: `goh-RON-tsoh`},{pl: `deszcz`, sw: `mvua`, ipa: `deshch`},{pl: `śnieg`, sw: `theluji`, ipa: `shnyek`},{pl: `wiatr`, sw: `upepo`, ipa: `vyatr`},{pl: `słońce`, sw: `jua`, ipa: `SWON-tseh`},{pl: `parasol`, sw: `mwavuli`, ipa: `pah-RAH-sol`},{pl: `kurtka`, sw: `koti`, ipa: `KOORT-kah`}], phrases: [{pl: `Jaka jest pogoda?`, sw: `Hali ya hewa ikoje?`, ipa: `YAH-kah yest poh-GOH-dah`},{pl: `Jest zimno.`, sw: `Kuna baridi.`, ipa: `yest ZHEEM-noh`},{pl: `Pada deszcz.`, sw: `Mvua inanyesha.`, ipa: `PAH-dah deshch`},{pl: `Pada śnieg.`, sw: `Theluji inanyesha.`, ipa: `PAH-dah shnyek`},{pl: `Potrzebuję parasola.`, sw: `Ninahitaji mwavuli.`, ipa: `poh-tsheh-BOO-yeh pah-rah-SOH-lah`},{pl: `Dzisiaj zostaję w hotelu.`, sw: `Leo nabaki hotelini.`, ipa: `JEE-shai zoh-STAH-yeh v hoh-TEH-loo`}], grammar: `Kwa hali ya hewa, Kipolishi mara nyingi hutumia miundo isiyo na “mimi” au “wewe,” kama “Jest zimno” na “Pada deszcz.” Usitafsiri moja kwa moja kutoka Kiswahili; jifunze misemo kamili.`, practice: [`Uliza hali ya hewa ikoje.`,`Sema kuna baridi.`,`Sema mvua inanyesha.`,`Sema unahitaji mwavuli.`,`Tunga mpango wa siku ukitumia “dzisiaj.”`]},{day: 18, title: `Familia na watu`, title_native: `Rodzina i ludzie`, focus: `Katika mazungumzo ya kawaida na wenyeji, mara nyingi watu huuliza unasafiri na nani. Leo unajifunza kuzungumzia familia na marafiki kwa urahisi.`, vocab: [{pl: `rodzina`, sw: `familia`, ipa: `roh-JEE-nah`},{pl: `mama`, sw: `mama`, ipa: `MAH-mah`},{pl: `tata`, sw: `baba`, ipa: `TAH-tah`},{pl: `brat`, sw: `kaka / ndugu wa kiume`, ipa: `brat`},{pl: `siostra`, sw: `dada`, ipa: `SHOS-trah`},{pl: `dziecko`, sw: `mtoto`, ipa: `JETS-koh`},{pl: `przyjaciel`, sw: `rafiki wa kiume`, ipa: `pshi-YAH-chel`},{pl: `przyjaciółka`, sw: `rafiki wa kike`, ipa: `pshi-yah-CHOO-kah`},{pl: `mąż`, sw: `mume`, ipa: `monsh`},{pl: `żona`, sw: `mke`, ipa: `ZHOH-nah`}], phrases: [{pl: `To jest moja rodzina.`, sw: `Hii ni familia yangu.`, ipa: `toh yest MOH-yah roh-JEE-nah`},{pl: `Podróżuję z przyjacielem.`, sw: `Ninasafiri na rafiki wa kiume.`, ipa: `poh-droh-ZHOO-yeh z pshi-YAH-cheh-lem`},{pl: `Podróżuję z rodziną.`, sw: `Ninasafiri na familia.`, ipa: `poh-droh-ZHOO-yeh z roh-JEE-nom`},{pl: `Mam brata i siostrę.`, sw: `Nina kaka na dada.`, ipa: `mam BRAH-tah ee SHOS-treh`},{pl: `To jest mój mąż.`, sw: `Huyu ni mume wangu.`, ipa: `toh yest mooy monsh`},{pl: `To jest moja żona.`, sw: `Huyu ni mke wangu.`, ipa: `toh yest MOH-yah ZHOH-nah`}], grammar: `“Kusafiri na” ni “podróżuję z...” Kwenye Kipolishi, baada ya “z,” majina mara nyingi hubadilika, lakini kwa misemo ya kawaida unaweza kuyakariri kama vipande. “Mój” na “moja” zote ni “yangu,” lakini hutegemea nomino.`, practice: [`Sema unasafiri na familia.`,`Sema una kaka na dada.`,`Mtambulishe rafiki yako kwa Kipolishi.`,`Sema “Hii ni familia yangu.”`,`Taja watu watano wa familia kwa Kipolishi.`]},{day: 19, title: `Mazungumzo ya kirafiki`, title_native: `Przyjazna rozmowa`, focus: `Leo unajifunza kuanzisha mazungumzo madogo na mtu wa Poland. Mada ni rahisi: unatoka wapi, unapenda nini, na unaonaje mji.`, vocab: [{pl: `rozmowa`, sw: `mazungumzo`, ipa: `roz-MOH-vah`},{pl: `miasto`, sw: `mji`, ipa: `MYAS-toh`},{pl: `ładny`, sw: `mzuri`, ipa: `WAD-nih`},{pl: `piękny`, sw: `mzuri sana / maridadi`, ipa: `PYENK-nih`},{pl: `lubić`, sw: `kupenda`, ipa: `LOO-beech`},{pl: `podoba się`, sw: `inapendeza`, ipa: `poh-DOH-bah shyeh`},{pl: `muzyka`, sw: `muziki`, ipa: `moo-ZIH-kah`},{pl: `film`, sw: `filamu`, ipa: `film`},{pl: `książka`, sw: `kitabu`, ipa: `KSHYONSH-kah`},{pl: `spacer`, sw: `matembezi`, ipa: `SPAH-tser`}], phrases: [{pl: `Skąd jesteś?`, sw: `Unatoka wapi?`, ipa: `skont YES-tesh`},{pl: `Jestem z Kenii.`, sw: `Ninatoka Kenya.`, ipa: `YES-tem z KEH-nyi`},{pl: `Podoba mi się Warszawa.`, sw: `Warsaw inanipendeza.`, ipa: `poh-DOH-bah mee shyeh var-SHAH-vah`},{pl: `Lubię polskie jedzenie.`, sw: `Napenda chakula cha Kipolishi.`, ipa: `LOO-byeh POL-skyeh yed-ZEH-nyeh`},{pl: `To piękne miasto.`, sw: `Huu ni mji mzuri sana.`, ipa: `toh PYENK-neh MYAS-toh`},{pl: `Miło było porozmawiać.`, sw: `Ilikuwa vizuri kuzungumza.`, ipa: `MEE-woh BIH-woh poh-roz-MAH-vyach`}], grammar: `“Lubię” maana yake ni “napenda,” na hutumika kwa vitu na shughuli. “Podoba mi się...” ni kama “inanipendeza,” mara nyingi hutumika kwa miji, muziki au vitu unavyoviona. Hii inaonekana ya asili zaidi kuliko kutafsiri moja kwa moja.`, practice: [`Sema unatoka nchi yako.`,`Sema unapenda chakula cha Kipolishi.`,`Sema Warsaw inanipendeza.`,`Taja kitu kimoja unachopenda kwa “Lubię...”`,`Maliza mazungumzo kwa kusema ilikuwa vizuri kuzungumza.`]},{day: 20, title: `Makumbusho na vivutio`, title_native: `Muzea i atrakcje`, focus: `Poland ina makumbusho mengi, majumba ya kihistoria na miji ya kale. Leo unajifunza kununua tiketi, kuuliza saa za kufunguliwa na kufuata sheria za mahali.`, vocab: [{pl: `muzeum`, sw: `makumbusho`, ipa: `moo-ZEH-oom`},{pl: `zamek`, sw: `kasri`, ipa: `ZAH-mek`},{pl: `bilet normalny`, sw: `tiketi ya kawaida`, ipa: `BEE-let nor-MAL-nih`},{pl: `bilet ulgowy`, sw: `tiketi ya punguzo`, ipa: `BEE-let ool-GOH-vih`},{pl: `godziny otwarcia`, sw: `saa za kufunguliwa`, ipa: `goh-JEE-nih ot-FAR-chah`},{pl: `wejście`, sw: `kuingia / mlango`, ipa: `VEY-shchyeh`},{pl: `wyjście`, sw: `kutoka`, ipa: `VIH-shchyeh`},{pl: `zdjęcie`, sw: `picha`, ipa: `ZDYEHN-chyeh`},{pl: `przewodnik`, sw: `mwongoza watalii`, ipa: `psheh-VOD-neek`},{pl: `wystawa`, sw: `maonyesho`, ipa: `vih-STAH-vah`}], phrases: [{pl: `Poproszę jeden bilet normalny.`, sw: `Naomba tiketi moja ya kawaida.`, ipa: `poh-PROH-sheh YEH-den BEE-let nor-MAL-nih`},{pl: `O której otwieracie?`, sw: `Mnafungua saa ngapi?`, ipa: `oh KTOO-rey ot-fyeh-RAH-chyeh`},{pl: `Czy można robić zdjęcia?`, sw: `Je, naweza kupiga picha?`, ipa: `chih MOZH-nah ROH-beech ZDYEHN-chah`},{pl: `Gdzie jest wejście?`, sw: `Mlango wa kuingia uko wapi?`, ipa: `gjeh yest VEY-shchyeh`},{pl: `Czy jest przewodnik po angielsku?`, sw: `Je, kuna mwongoza kwa Kiingereza?`, ipa: `chih yest psheh-VOD-neek poh an-GYEL-skoo`},{pl: `Ta wystawa jest ciekawa.`, sw: `Maonyesho haya yanavutia.`, ipa: `tah vih-STAH-vah yest chyeh-KAH-vah`}], grammar: `“Czy można...” ni muhimu kwa kuomba ruhusa: “Czy można robić zdjęcia?” Unaweza pia kusema “Czy można wejść?” kwa “Je, tunaweza kuingia?” Hii ni njia ya heshima na ya kawaida.`, practice: [`Omba tiketi moja ya kawaida.`,`Uliza kama unaweza kupiga picha.`,`Uliza mlango wa kuingia uko wapi.`,`Uliza kama kuna mwongoza kwa Kiingereza.`,`Sema maonyesho yanavutia.`]},{day: 21, title: `Kwenye kituo cha treni`, title_native: `Na dworcu kolejowym`, focus: `Leo unajifunza kusafiri kati ya miji ya Poland kwa treni, kwa mfano Warsaw kwenda Kraków. Utahitaji kujua jukwaa, kuchelewa na tiketi.`, vocab: [{pl: `dworzec kolejowy`, sw: `kituo cha treni`, ipa: `DVOH-zhets koh-leh-YOH-vih`},{pl: `peron`, sw: `jukwaa la treni`, ipa: `PEH-ron`},{pl: `tor`, sw: `reli / njia ya treni`, ipa: `tor`},{pl: `pociąg`, sw: `treni`, ipa: `POH-chonk`},{pl: `opóźnienie`, sw: `kuchelewa`, ipa: `oh-poozh-NYEH-nyeh`},{pl: `odjazd`, sw: `kuondoka`, ipa: `OD-yazd`},{pl: `przyjazd`, sw: `kuwasili`, ipa: `PSHIH-yazd`},{pl: `miejsce`, sw: `kiti / nafasi`, ipa: `MYEYS-tseh`},{pl: `wagon`, sw: `behewa`, ipa: `VAH-gon`},{pl: `konduktor`, sw: `kondakta`, ipa: `kon-DOOK-tor`}], phrases: [{pl: `Z którego peronu odjeżdża pociąg?`, sw: `Treni inaondoka jukwaa gani?`, ipa: `z KTOO-reh-goh peh-ROH-noo od-YEZH-jah POH-chonk`},{pl: `Czy ten pociąg jedzie do Krakowa?`, sw: `Je, treni hii inaenda Kraków?`, ipa: `chih ten POH-chonk YED-zheh doh kra-KOH-vah`},{pl: `Pociąg ma opóźnienie.`, sw: `Treni imechelewa.`, ipa: `POH-chonk mah oh-poozh-NYEH-nyeh`},{pl: `Mam miejsce przy oknie.`, sw: `Nina kiti karibu na dirisha.`, ipa: `mam MYEYS-tseh pshi OK-nyeh`},{pl: `Gdzie jest wagon numer trzy?`, sw: `Behewa namba tatu liko wapi?`, ipa: `gjeh yest VAH-gon NOO-mer tshih`},{pl: `Poproszę pomoc z biletem.`, sw: `Naomba msaada na tiketi.`, ipa: `poh-PROH-sheh POH-mots z BEE-leh-tem`}], grammar: `“Do” maana yake ni “kwenda/kwenye” kwa miji mingi, kama “do Krakowa” au “do Warszawy.” Majina ya miji hubadilika baada ya “do,” lakini ukisema jina la msingi watu bado watakuelewa. Ratiba za treni hutumia sana “odjazd” na “przyjazd.”`, practice: [`Uliza treni inaondoka jukwaa gani.`,`Uliza kama treni inaenda Kraków.`,`Sema treni imechelewa.`,`Sema una kiti karibu na dirisha.`,`Tafuta kwenye ramani miji miwili ya Poland na sema “jadę do...”`]},{day: 22, title: `Teksi na huduma za usafiri`, title_native: `Taxi i przejazdy`, focus: `Wakati mwingine ni rahisi kutumia teksi au huduma ya usafiri mjini Warsaw au Gdańsk. Leo unajifunza kueleza unakoenda, kuuliza gharama na kuthibitisha njia.`, vocab: [{pl: `taxi`, sw: `teksi`, ipa: `TAK-see`},{pl: `adres`, sw: `anwani`, ipa: `AH-dres`},{pl: `centrum`, sw: `katikati ya mji`, ipa: `TSEN-troom`},{pl: `hotel`, sw: `hoteli`, ipa: `HOH-tel`},{pl: `lotnisko`, sw: `uwanja wa ndege`, ipa: `lot-NEE-skoh`},{pl: `kierowca`, sw: `dereva`, ipa: `kyeh-ROF-tsah`},{pl: `droga`, sw: `njia / barabara`, ipa: `DROH-gah`},{pl: `szybko`, sw: `haraka`, ipa: `SHIP-koh`},{pl: `wolno`, sw: `polepole`, ipa: `VOL-noh`},{pl: `tutaj`, sw: `hapa`, ipa: `TOO-tai`}], phrases: [{pl: `Proszę jechać do hotelu.`, sw: `Tafadhali nenda hoteli.`, ipa: `PROH-sheh YEH-hach doh hoh-TEH-loo`},{pl: `To jest adres.`, sw: `Hii ndiyo anwani.`, ipa: `toh yest AH-dres`},{pl: `Ile będzie kosztować przejazd?`, sw: `Safari itagharimu kiasi gani?`, ipa: `EE-leh BEN-jyeh kosh-TOH-vach PSHEH-yazd`},{pl: `Proszę zatrzymać się tutaj.`, sw: `Tafadhali simama hapa.`, ipa: `PROH-sheh zah-tshi-MAHCH shyeh TOO-tai`},{pl: `Czy możemy jechać szybciej?`, sw: `Tunaweza kwenda haraka zaidi?`, ipa: `chih MOH-zheh-mih YEH-hach SHIP-chey`},{pl: `Dziękuję za przejazd.`, sw: `Asante kwa safari.`, ipa: `jen-KOO-yeh zah PSHEH-yazd`}], grammar: `“Jechać” ni kwenda kwa chombo cha usafiri. “Iść” ni kwenda kwa miguu. Kwenye teksi, tumia “Proszę jechać do...” kwa kusema “tafadhali nenda...” Hii ni rahisi na ya heshima.`, practice: [`Mwambie dereva aende hoteli.`,`Mwonyeshe anwani kwa Kipolishi.`,`Uliza safari itagharimu kiasi gani.`,`Omba dereva asimame hapa.`,`Sema asante kwa safari.`]},{day: 23, title: `Simu, intaneti na mawasiliano`, title_native: `Telefon, internet i kontakt`, focus: `Ukiwa safarini, unaweza kuhitaji SIM kadi, Wi-Fi au kuchaji simu. Leo unajifunza maneno ya mawasiliano ya kisasa.`, vocab: [{pl: `telefon`, sw: `simu`, ipa: `teh-LEH-fon`},{pl: `ładowarka`, sw: `chaja`, ipa: `wah-doh-VAR-kah`},{pl: `bateria`, sw: `betri`, ipa: `bah-TEH-ryah`},{pl: `internet`, sw: `intaneti`, ipa: `in-TER-net`},{pl: `Wi-Fi`, sw: `Wi-Fi`, ipa: `VAI-fai`},{pl: `hasło`, sw: `nenosiri`, ipa: `HAS-woh`},{pl: `karta SIM`, sw: `SIM kadi`, ipa: `KAR-tah seem`},{pl: `numer`, sw: `namba`, ipa: `NOO-mer`},{pl: `wiadomość`, sw: `ujumbe`, ipa: `vya-DOH-moshch`},{pl: `połączenie`, sw: `muunganisho / simu`, ipa: `poh-won-CHEH-nyeh`}], phrases: [{pl: `Czy jest Wi-Fi?`, sw: `Je, kuna Wi-Fi?`, ipa: `chih yest VAI-fai`},{pl: `Jakie jest hasło?`, sw: `Nenosiri ni nini?`, ipa: `YAH-kyeh yest HAS-woh`},{pl: `Potrzebuję karty SIM.`, sw: `Ninahitaji SIM kadi.`, ipa: `poh-tsheh-BOO-yeh KAR-tih seem`},{pl: `Mój telefon nie działa.`, sw: `Simu yangu haifanyi kazi.`, ipa: `mooy teh-LEH-fon nyeh JAH-wah`},{pl: `Gdzie mogę naładować telefon?`, sw: `Naweza kuchaji simu wapi?`, ipa: `gjeh MOH-geh nah-WAH-doh-vach teh-LEH-fon`},{pl: `Proszę wysłać wiadomość.`, sw: `Tafadhali tuma ujumbe.`, ipa: `PROH-sheh VIH-swach vya-DOH-moshch`}], grammar: `“Nie działa” maana yake ni “haifanyi kazi.” Unaweza kuitumia kwa simu, Wi-Fi, kadi au mashine: “Wi-Fi nie działa.” Ni msemo mfupi lakini muhimu sana kwa msafiri.`, practice: [`Uliza kama kuna Wi-Fi.`,`Uliza nenosiri.`,`Sema simu yako haifanyi kazi.`,`Sema unahitaji SIM kadi.`,`Uliza unaweza kuchaji simu wapi.`]},{day: 24, title: `Kukodisha na huduma`, title_native: `Wynajem i usługi`, focus: `Leo unajifunza lugha ya huduma ndogo: kukodisha baiskeli, kutumia kufuli, kuuliza sheria na muda. Hii ni muhimu ukiwa kwenye miji yenye baiskeli kama Wrocław au Gdańsk.`, vocab: [{pl: `wynajem`, sw: `kukodisha`, ipa: `vih-NAH-yem`},{pl: `rower`, sw: `baiskeli`, ipa: `ROH-ver`},{pl: `samochód`, sw: `gari`, ipa: `sah-MOH-hoot`},{pl: `klucz`, sw: `ufunguo`, ipa: `klooch`},{pl: `zamek`, sw: `kufuli / kasri`, ipa: `ZAH-mek`},{pl: `godzina`, sw: `saa`, ipa: `goh-JEE-nah`},{pl: `dzień`, sw: `siku`, ipa: `jen`},{pl: `kaucja`, sw: `dhamana`, ipa: `KOW-tsyah`},{pl: `podpis`, sw: `sahihi`, ipa: `POD-pees`},{pl: `regulamin`, sw: `sheria / kanuni`, ipa: `reh-goo-LAH-meen`}], phrases: [{pl: `Chcę wynająć rower.`, sw: `Nataka kukodisha baiskeli.`, ipa: `htseh vih-NAH-yonch ROH-ver`},{pl: `Na jedną godzinę.`, sw: `Kwa saa moja.`, ipa: `nah YED-nom goh-JEE-neh`},{pl: `Ile wynosi kaucja?`, sw: `Dhamana ni kiasi gani?`, ipa: `EE-leh vih-NOH-see KOW-tsyah`},{pl: `Gdzie mam podpisać?`, sw: `Nisaini wapi?`, ipa: `gjeh mam pod-PEE-sach`},{pl: `Czy mogę oddać tutaj?`, sw: `Naweza kurudisha hapa?`, ipa: `chih MOH-geh OD-dach TOO-tai`},{pl: `Proszę wyjaśnić regulamin.`, sw: `Tafadhali eleza kanuni.`, ipa: `PROH-sheh vih-YASH-neech reh-goo-LAH-meen`}], grammar: `“Chcę” maana yake ni “nataka.” Ni neno la moja kwa moja lakini la kawaida. Ili kulifanya liwe la heshima zaidi, ongeza “proszę” au tumia sauti ya upole, hasa kwenye huduma.`, practice: [`Sema unataka kukodisha baiskeli.`,`Sema kwa saa moja.`,`Uliza dhamana ni kiasi gani.`,`Uliza unasaini wapi.`,`Uliza kama unaweza kurudisha kitu hapa.`]},{day: 25, title: `Nyumba ya wageni na matatizo madogo`, title_native: `Nocleg i małe problemy`, focus: `Ukiwa kwenye hoteli, hosteli au Airbnb Poland, unaweza kukutana na tatizo dogo. Leo unajifunza kueleza kwamba kitu hakifanyi kazi au unahitaji kitu chumbani.`, vocab: [{pl: `nocleg`, sw: `malazi`, ipa: `NOTS-leg`},{pl: `pokój`, sw: `chumba`, ipa: `POH-kooy`},{pl: `drzwi`, sw: `mlango`, ipa: `dzhvee`},{pl: `okno`, sw: `dirisha`, ipa: `OK-noh`},{pl: `światło`, sw: `taa`, ipa: `SHFYAT-woh`},{pl: `ciepła woda`, sw: `maji ya moto`, ipa: `CHPYEH-wah VOH-dah`},{pl: `ręcznik`, sw: `taulo`, ipa: `RENCH-neek`},{pl: `pościel`, sw: `mashuka`, ipa: `POSH-chel`},{pl: `hałas`, sw: `kelele`, ipa: `HAH-was`},{pl: `klimatyzacja`, sw: `kiyoyozi`, ipa: `klee-mah-tih-ZAH-tsyah`}], phrases: [{pl: `Światło nie działa.`, sw: `Taa haifanyi kazi.`, ipa: `SHFYAT-woh nyeh JAH-wah`},{pl: `Nie ma ciepłej wody.`, sw: `Hakuna maji ya moto.`, ipa: `nyeh mah CHPYEH-wey VOH-dih`},{pl: `Potrzebuję ręcznika.`, sw: `Ninahitaji taulo.`, ipa: `poh-tsheh-BOO-yeh RENCH-nee-kah`},{pl: `W pokoju jest hałas.`, sw: `Kuna kelele chumbani.`, ipa: `v poh-KOH-yoo yest HAH-was`},{pl: `Czy mogę zmienić pokój?`, sw: `Naweza kubadilisha chumba?`, ipa: `chih MOH-geh ZMYEH-neech POH-kooy`},{pl: `Drzwi się nie zamykają.`, sw: `Mlango haufungiki.`, ipa: `dzhvee shyeh nyeh zah-MIH-kah-yom`}], grammar: `“Nie ma...” maana yake ni “hakuna.” Ni muundo muhimu sana: “Nie ma wody,” “Nie ma Wi-Fi,” “Nie ma ręcznika.” Kwa matatizo, ongea kwa utulivu na tumia “proszę” kuonyesha heshima.`, practice: [`Sema taa haifanyi kazi.`,`Sema hakuna maji ya moto.`,`Omba taulo.`,`Uliza kama unaweza kubadilisha chumba.`,`Taja matatizo matatu ya hoteli kwa Kipolishi.`]},{day: 26, title: `Kutoa maoni na malalamiko kwa heshima`, title_native: `Opinie i uprzejme skargi`, focus: `Wakati mwingine msafiri anahitaji kusema kitu si sahihi. Leo unajifunza kutoa maoni, kuomba suluhisho na kubaki mwenye heshima katika Poland.`, vocab: [{pl: `problem`, sw: `tatizo`, ipa: `PROH-blem`},{pl: `błąd`, sw: `kosa`, ipa: `bwont`},{pl: `zimny`, sw: `baridi`, ipa: `ZHEEM-nih`},{pl: `brudny`, sw: `chafu`, ipa: `BROOD-nih`},{pl: `czysty`, sw: `safi`, ipa: `CHIH-stih`},{pl: `wolny`, sw: `polepole`, ipa: `VOL-nih`},{pl: `szybki`, sw: `haraka`, ipa: `SHIP-kee`},{pl: `przepraszam`, sw: `samahani`, ipa: `psheh-PRAH-sham`},{pl: `rozwiązanie`, sw: `suluhisho`, ipa: `roz-vyon-ZAH-nyeh`},{pl: `manager`, sw: `meneja`, ipa: `MEH-nah-jer`}], phrases: [{pl: `Przepraszam, jest problem.`, sw: `Samahani, kuna tatizo.`, ipa: `psheh-PRAH-sham yest PROH-blem`},{pl: `To nie jest moje zamówienie.`, sw: `Hii si oda yangu.`, ipa: `toh nyeh yest MOH-yeh zah-moo-VYEH-nyeh`},{pl: `Jedzenie jest zimne.`, sw: `Chakula ni baridi.`, ipa: `yed-ZEH-nyeh yest ZHEEM-neh`},{pl: `Pokój jest brudny.`, sw: `Chumba ni chafu.`, ipa: `POH-kooy yest BROOD-nih`},{pl: `Czy można to naprawić?`, sw: `Je, inawezekana kurekebisha hii?`, ipa: `chih MOZH-nah toh nah-PRAH-veech`},{pl: `Chciałbym rozmawiać z managerem.`, sw: `Ningependa kuzungumza na meneja, mwanaume akisema.`, ipa: `HCHAW-bim roz-MAH-vyach z MEH-nah-jer-em`}], grammar: `“Kuwa na malalamiko” kwa lugha ya heshima huanza vizuri na “Przepraszam.” “Chciałbym” hutumiwa na mwanaume kwa “ningependa,” na “chciałabym” hutumiwa na mwanamke. Ni laini zaidi kuliko “chcę.”`, practice: [`Sema kuna tatizo kwa heshima.`,`Sema hii si oda yako.`,`Sema chakula ni baridi.`,`Uliza kama inawezekana kurekebisha.`,`Omba kuzungumza na meneja kwa heshima.`]},{day: 27, title: `Kualika na kukubali`, title_native: `Zaproszenia i zgody`, focus: `Leo unajifunza lugha ya kijamii: kukubali mwaliko, kukataa kwa adabu na kupanga kukutana. Hii itakusaidia ukiwa na wenyeji au wasafiri wengine Poland.`, vocab: [{pl: `zaproszenie`, sw: `mwaliko`, ipa: `zah-proh-SHEH-nyeh`},{pl: `spotkanie`, sw: `mkutano / kukutana`, ipa: `spot-KAH-nyeh`},{pl: `kawa`, sw: `kahawa`, ipa: `KAH-vah`},{pl: `kolacja`, sw: `chakula cha jioni`, ipa: `koh-LAH-tsyah`},{pl: `czas`, sw: `muda`, ipa: `chas`},{pl: `chętnie`, sw: `kwa furaha`, ipa: `HENCH-nyeh`},{pl: `niestety`, sw: `kwa bahati mbaya`, ipa: `nyeh-STEH-tih`},{pl: `może`, sw: `labda`, ipa: `MOH-zheh`},{pl: `razem`, sw: `pamoja`, ipa: `RAH-zem`},{pl: `plan`, sw: `mpango`, ipa: `plan`}], phrases: [{pl: `Masz czas dzisiaj?`, sw: `Una muda leo?`, ipa: `mash chas JEE-shai`},{pl: `Chętnie pójdę na kawę.`, sw: `Nitaenda kunywa kahawa kwa furaha.`, ipa: `HENCH-nyeh POY-deh nah KAH-veh`},{pl: `Niestety, nie mogę.`, sw: `Kwa bahati mbaya, siwezi.`, ipa: `nyeh-STEH-tih nyeh MOH-geh`},{pl: `Może jutro?`, sw: `Labda kesho?`, ipa: `MOH-zheh YOO-troh`},{pl: `Spotkajmy się o szóstej.`, sw: `Tukutane saa kumi na mbili jioni / saa sita kwa mfumo wa Ulaya.`, ipa: `spot-KAI-mih shyeh oh SHOOS-tey`},{pl: `To dobry plan.`, sw: `Huo ni mpango mzuri.`, ipa: `toh DOH-bri plan`}], grammar: `“Chętnie” ni neno zuri sana la kukubali mwaliko kwa uchangamfu. “Niestety” husaidia kukataa bila kuonekana mkali. Kwa kupanga muda, tumia “o” kabla ya saa: “o szóstej.”`, practice: [`Uliza mtu kama ana muda leo.`,`Kubali kwenda kunywa kahawa.`,`Kataa kwa adabu.`,`Pendekeza kesho.`,`Sema huo ni mpango mzuri.`]},{day: 28, title: `Kusafiri nje ya mji`, title_native: `Wycieczka poza miasto`, focus: `Poland ina maeneo mengi ya kutembelea nje ya miji mikubwa, kama Wieliczka, Zakopane au Malbork. Leo unajifunza kupanga safari fupi ya siku.`, vocab: [{pl: `wycieczka`, sw: `safari ya kutembelea`, ipa: `vih-CHYECH-kah`},{pl: `góry`, sw: `milima`, ipa: `GOO-ri`},{pl: `morze`, sw: `bahari`, ipa: `MOH-zheh`},{pl: `jezioro`, sw: `ziwa`, ipa: `yeh-ZYOH-roh`},{pl: `las`, sw: `msitu`, ipa: `las`},{pl: `bilet powrotny`, sw: `tiketi ya kurudi`, ipa: `BEE-let poh-VROT-nih`},{pl: `rano`, sw: `asubuhi`, ipa: `RAH-noh`},{pl: `wieczorem`, sw: `jioni`, ipa: `vyeh-CHOH-rem`},{pl: `przewodnik`, sw: `mwongoza watalii`, ipa: `psheh-VOD-neek`},{pl: `plan podróży`, sw: `ratiba ya safari`, ipa: `plan poh-DROO-zhih`}], phrases: [{pl: `Chcę pojechać do Zakopanego.`, sw: `Nataka kwenda Zakopane.`, ipa: `htseh poh-YEH-hach doh zah-koh-PAH-neh-goh`},{pl: `Poproszę bilet powrotny.`, sw: `Naomba tiketi ya kurudi.`, ipa: `poh-PROH-sheh BEE-let poh-VROT-nih`},{pl: `O której wraca autobus?`, sw: `Basi linarudi saa ngapi?`, ipa: `oh KTOO-rey VRAH-tsah ow-TOH-boos`},{pl: `Czy potrzebny jest przewodnik?`, sw: `Je, mwongoza anahitajika?`, ipa: `chih poh-TSHEB-nih yest psheh-VOD-neek`},{pl: `Jedziemy rano.`, sw: `Tunaenda asubuhi kwa usafiri.`, ipa: `yeh-JEH-mih RAH-noh`},{pl: `Wracamy wieczorem.`, sw: `Tunarudi jioni.`, ipa: `vrah-TSAH-mih vyeh-CHOH-rem`}], grammar: `“Jechać” na “pojechać” zote zinahusiana na kwenda kwa chombo cha usafiri. “Pojechać” mara nyingi hutumika kwa safari moja iliyopangwa. Kwa kusema “nataka kwenda,” tumia “Chcę pojechać do...”`, practice: [`Sema unataka kwenda Zakopane.`,`Omba tiketi ya kurudi.`,`Uliza basi linarudi saa ngapi.`,`Sema mnaenda asubuhi.`,`Sema mnarudi jioni.`]},{day: 29, title: `Kujieleza zaidi`, title_native: `Mówienie o sobie więcej`, focus: `Sasa una uwezo wa kuzungumza zaidi kuhusu wewe mwenyewe. Leo unaunganisha kazi, maslahi, safari na maoni yako kwa mazungumzo marefu kidogo.`, vocab: [{pl: `pracuję`, sw: `ninafanya kazi`, ipa: `prah-TSOO-yeh`},{pl: `studiuję`, sw: `ninasoma`, ipa: `stoo-DYOO-yeh`},{pl: `podróżuję`, sw: `ninasafiri`, ipa: `poh-droh-ZHOO-yeh`},{pl: `mieszkam`, sw: `ninaishi`, ipa: `MYESH-kam`},{pl: `lubię`, sw: `napenda`, ipa: `LOO-byeh`},{pl: `interesuję się`, sw: `navutiwa na`, ipa: `in-teh-reh-SOO-yeh shyeh`},{pl: `historia`, sw: `historia`, ipa: `hee-STOH-ryah`},{pl: `kultura`, sw: `utamaduni`, ipa: `kool-TOO-rah`},{pl: `sport`, sw: `michezo`, ipa: `sport`},{pl: `fotografia`, sw: `upigaji picha`, ipa: `foh-toh-GRAH-fyah`}], phrases: [{pl: `Mieszkam w Dar es Salaam.`, sw: `Ninaishi Dar es Salaam.`, ipa: `MYESH-kam v dar es sah-LAAM`},{pl: `Pracuję w firmie turystycznej.`, sw: `Ninafanya kazi kwenye kampuni ya utalii.`, ipa: `prah-TSOO-yeh v FEER-myeh too-rih-STIHCH-ney`},{pl: `Studiuję języki.`, sw: `Ninasoma lugha.`, ipa: `stoo-DYOO-yeh YEN-zhih-kee`},{pl: `Interesuję się historią.`, sw: `Navutiwa na historia.`, ipa: `in-teh-reh-SOO-yeh shyeh hee-STOH-ryom`},{pl: `Lubię robić zdjęcia.`, sw: `Napenda kupiga picha.`, ipa: `LOO-byeh ROH-beech ZDYEHN-chah`},{pl: `Podróżuję po Polsce.`, sw: `Ninasafiri ndani ya Poland.`, ipa: `poh-droh-ZHOO-yeh poh POL-scheh`}], grammar: `Vitenzi vingi vya “mimi” huishia kwa “-ę” au “-am,” kama “lubię,” “pracuję,” na “mieszkam.” Huwezi kutabiri kila kitu mara moja, lakini unaweza kukariri sentensi kamili kuhusu maisha yako. Hizi zitakusaidia sana kwenye mazungumzo ya kawaida.`, practice: [`Sema unaishi wapi kwa Kipolishi.`,`Sema unafanya kazi au unasoma nini.`,`Sema unapenda kupiga picha.`,`Sema navutiwa na historia au utamaduni.`,`Tengeneza utambulisho wa sentensi tano kwa Kipolishi.`]},{day: 30, title: `Mapitio ya safari nzima`, title_native: `Powtórka całej podróży`, focus: `Leo unarudia kila kitu muhimu kwa safari yako Poland: salamu, hoteli, chakula, usafiri, ununuzi na dharura. Lengo ni kuongea kwa ujasiri hata kama sentensi zako ni rahisi.`, vocab: [{pl: `rozumiem`, sw: `ninaelewa`, ipa: `roh-ZOO-myem`},{pl: `nie rozumiem`, sw: `sielewi`, ipa: `nyeh roh-ZOO-myem`},{pl: `mówię`, sw: `naongea`, ipa: `MOO-vyeh`},{pl: `potrzebuję`, sw: `ninahitaji`, ipa: `poh-tsheh-BOO-yeh`},{pl: `szukam`, sw: `natafuta`, ipa: `SHOO-kam`},{pl: `chcę`, sw: `nataka`, ipa: `htseh`},{pl: `mogę`, sw: `ninaweza`, ipa: `MOH-geh`},{pl: `mam`, sw: `nina`, ipa: `mam`},{pl: `nie mam`, sw: `sina`, ipa: `nyeh mam`},{pl: `dziękuję`, sw: `asante`, ipa: `jen-KOO-yeh`}], phrases: [{pl: `Nie mówię dobrze po polsku.`, sw: `Sizungumzi Kipolishi vizuri.`, ipa: `nyeh MOO-vyeh DOH-bzheh poh POL-skoo`},{pl: `Czy może pan pomóc?`, sw: `Je, bwana anaweza kusaidia?`, ipa: `chih MOH-zheh pahn POH-moots`},{pl: `Czy może pani pomóc?`, sw: `Je, bibi anaweza kusaidia?`, ipa: `chih MOH-zheh PAH-nee POH-moots`},{pl: `Szukam hotelu.`, sw: `Natafuta hoteli.`, ipa: `SHOO-kam hoh-TEH-loo`},{pl: `Chcę kupić bilet.`, sw: `Nataka kununua tiketi.`, ipa: `htseh KOO-peech BEE-let`},{pl: `Dziękuję za pomoc.`, sw: `Asante kwa msaada.`, ipa: `jen-KOO-yeh zah POH-mots`}], grammar: `Usafiri wa lugha hauhitaji ukamilifu; unahitaji misemo inayofanya kazi. Tumia vitenzi vya msingi kama “mam,” “chcę,” “mogę,” “szukam,” na “potrzebuję.” Ukikwama, sema “Nie rozumiem” au “Czy może pan/pani pomóc?”`, practice: [`Jitambulishe, sema unatoka wapi na kwamba unasafiri Poland.`,`Uliza msaada kwa mtu rasmi.`,`Omba tiketi, maji na bili kwa “Poproszę.”`,`Eleza tatizo moja la hoteli au usafiri.`,`Fanya mazungumzo ya dakika moja ukitumia angalau misemo kumi uliyojifunza.`]}];

var CONVERSATIONS_SW_PL = [{id: 1, title: `Kuagiza kwenye mkahawa`, scene: `Uko kwenye mkahawa mdogo karibu na Rynek Główny huko Kraków. Unataka kahawa, keki na baadaye bili.`, lines: [{who: `them`, pl: `Dzień dobry, co podać?`, sw: `Habari za mchana, nikuletee nini?`},{who: `you`, pl: `Dzień dobry, poproszę kawę.`, sw: `Habari za mchana, naomba kahawa.`},{who: `them`, pl: `Z mlekiem czy bez mleka?`, sw: `Na maziwa au bila maziwa?`},{who: `you`, pl: `Z mlekiem, proszę.`, sw: `Na maziwa, tafadhali.`},{who: `them`, pl: `Czy coś jeszcze?`, sw: `Kuna kitu kingine?`},{who: `you`, pl: `Tak, poproszę ciasto.`, sw: `Ndiyo, naomba keki.`},{who: `them`, pl: `Mamy sernik i ciasto czekoladowe.`, sw: `Tuna cheesecake na keki ya chokoleti.`},{who: `you`, pl: `Poproszę sernik.`, sw: `Naomba cheesecake.`},{who: `them`, pl: `Proszę bardzo.`, sw: `Karibu.`},{who: `you`, pl: `Dziękuję, a potem poproszę rachunek.`, sw: `Asante, na baadaye naomba bili.`},{who: `them`, pl: `Oczywiście.`, sw: `Bila shaka.`}]},{id: 2, title: `Kuingia hoteli`, scene: `Umefika hoteli huko Warsaw baada ya safari ndefu. Una nafasi iliyohifadhiwa na unahitaji kujua kuhusu Wi-Fi na kifungua kinywa.`, lines: [{who: `them`, pl: `Dobry wieczór, witamy w hotelu.`, sw: `Habari za jioni, karibu hotelini.`},{who: `you`, pl: `Dobry wieczór, mam rezerwację.`, sw: `Habari za jioni, nina nafasi iliyohifadhiwa.`},{who: `them`, pl: `Na jakie nazwisko?`, sw: `Kwa jina gani?`},{who: `you`, pl: `Na nazwisko Cannon.`, sw: `Kwa jina Cannon.`},{who: `them`, pl: `Tak, mamy pana rezerwację.`, sw: `Ndiyo, tuna nafasi yako iliyohifadhiwa.`},{who: `you`, pl: `Czy jest śniadanie?`, sw: `Je, kuna kifungua kinywa?`},{who: `them`, pl: `Tak, śniadanie jest od siódmej.`, sw: `Ndiyo, kifungua kinywa ni kuanzia saa moja asubuhi.`},{who: `you`, pl: `Jakie jest hasło do Wi-Fi?`, sw: `Nenosiri la Wi-Fi ni nini?`},{who: `them`, pl: `Hasło to Warszawa2026.`, sw: `Nenosiri ni Warszawa2026.`},{who: `you`, pl: `Dziękuję, gdzie jest winda?`, sw: `Asante, lifti iko wapi?`},{who: `them`, pl: `Winda jest po prawej stronie.`, sw: `Lifti iko upande wa kulia.`}]},{id: 3, title: `Kuuliza njia mjini`, scene: `Uko Gdańsk na unataka kufika kwenye mji wa kale. Unamuuliza mtu njiani kwa heshima.`, lines: [{who: `you`, pl: `Przepraszam, gdzie jest stare miasto?`, sw: `Samahani, mji wa kale uko wapi?`},{who: `them`, pl: `Proszę iść prosto.`, sw: `Tafadhali nenda moja kwa moja.`},{who: `you`, pl: `Prosto, dobrze.`, sw: `Moja kwa moja, sawa.`},{who: `them`, pl: `Potem proszę skręcić w lewo.`, sw: `Kisha tafadhali geuka kushoto.`},{who: `you`, pl: `Czy to jest daleko?`, sw: `Je, ni mbali?`},{who: `them`, pl: `Nie, to jest blisko.`, sw: `Hapana, ni karibu.`},{who: `you`, pl: `Ile minut pieszo?`, sw: `Dakika ngapi kwa miguu?`},{who: `them`, pl: `Około dziesięć minut.`, sw: `Takriban dakika kumi.`},{who: `you`, pl: `Dziękuję za pomoc.`, sw: `Asante kwa msaada.`},{who: `them`, pl: `Nie ma za co.`, sw: `Karibu / hakuna shida.`}]},{id: 4, title: `Kula kwenye mgahawa`, scene: `Uko kwenye mgahawa wa Kipolishi huko Wrocław. Unataka kujaribu pierogi na kuuliza kama sahani ina nyama.`, lines: [{who: `them`, pl: `Dzień dobry, czy mają państwo rezerwację?`, sw: `Habari za mchana, mna nafasi iliyohifadhiwa?`},{who: `you`, pl: `Nie, stolik dla dwóch osób, proszę.`, sw: `Hapana, meza ya watu wawili tafadhali.`},{who: `them`, pl: `Proszę tutaj.`, sw: `Karibuni hapa.`},{who: `you`, pl: `Poproszę menu.`, sw: `Naomba menyu.`},{who: `them`, pl: `Oczywiście, proszę.`, sw: `Bila shaka, karibu.`},{who: `you`, pl: `Co pani poleca?`, sw: `Bibi unapendekeza nini?`},{who: `them`, pl: `Polecam pierogi ruskie.`, sw: `Ninapendekeza pierogi ruskie.`},{who: `you`, pl: `Czy to jest z mięsem?`, sw: `Je, hiyo ina nyama?`},{who: `them`, pl: `Nie, to jest z serem i ziemniakami.`, sw: `Hapana, ina jibini na viazi.`},{who: `you`, pl: `Świetnie, poproszę pierogi.`, sw: `Vizuri sana, naomba pierogi.`},{who: `them`, pl: `Czy coś do picia?`, sw: `Kinywaji chochote?`},{who: `you`, pl: `Poproszę wodę.`, sw: `Naomba maji.`}]},{id: 5, title: `Kununua tiketi ya tramu`, scene: `Uko Warsaw na unahitaji kununua tiketi ya tramu kwenda katikati ya mji. Unamuuliza mfanyakazi kwenye kioski.`, lines: [{who: `them`, pl: `Dzień dobry.`, sw: `Habari za mchana.`},{who: `you`, pl: `Dzień dobry, poproszę bilet jednorazowy.`, sw: `Habari za mchana, naomba tiketi ya safari moja.`},{who: `them`, pl: `Jeden bilet?`, sw: `Tiketi moja?`},{who: `you`, pl: `Tak, jeden bilet.`, sw: `Ndiyo, tiketi moja.`},{who: `them`, pl: `To będzie cztery złote.`, sw: `Itakuwa zloty nne.`},{who: `you`, pl: `Czy mogę zapłacić kartą?`, sw: `Naweza kulipa kwa kadi?`},{who: `them`, pl: `Tak, można.`, sw: `Ndiyo, inawezekana.`},{who: `you`, pl: `Czy ten tramwaj jedzie do centrum?`, sw: `Je, tramu hii inaenda katikati ya mji?`},{who: `them`, pl: `Tak, linia cztery jedzie do centrum.`, sw: `Ndiyo, laini ya nne inaenda katikati.`},{who: `you`, pl: `Dziękuję bardzo.`, sw: `Asante sana.`},{who: `them`, pl: `Proszę bardzo.`, sw: `Karibu.`}]},{id: 6, title: `Kununua zawadi`, scene: `Uko kwenye duka la zawadi huko Zakopane. Unatafuta ukumbusho mdogo na unataka kuuliza bei na rangi nyingine.`, lines: [{who: `them`, pl: `Dzień dobry, w czym mogę pomóc?`, sw: `Habari za mchana, ninaweza kusaidia nini?`},{who: `you`, pl: `Dzień dobry, szukam prezentu.`, sw: `Habari za mchana, natafuta zawadi.`},{who: `them`, pl: `Dla kogo?`, sw: `Kwa ajili ya nani?`},{who: `you`, pl: `Dla przyjaciela.`, sw: `Kwa ajili ya rafiki wa kiume.`},{who: `them`, pl: `Może ta pamiątka?`, sw: `Labda ukumbusho huu?`},{who: `you`, pl: `Ile to kosztuje?`, sw: `Hii inagharimu kiasi gani?`},{who: `them`, pl: `Trzydzieści złotych.`, sw: `Zloty thelathini.`},{who: `you`, pl: `Czy jest inny kolor?`, sw: `Je, kuna rangi nyingine?`},{who: `them`, pl: `Tak, mamy czerwony i niebieski.`, sw: `Ndiyo, tuna nyekundu na bluu.`},{who: `you`, pl: `Poproszę niebieski.`, sw: `Naomba bluu.`},{who: `them`, pl: `Czy potrzebuje pan torby?`, sw: `Je, bwana anahitaji mfuko?`},{who: `you`, pl: `Nie, dziękuję.`, sw: `Hapana, asante.`}]},{id: 7, title: `Kwenye duka la dawa`, scene: `Uko Poznań na una maumivu ya kichwa. Unaingia apteka kuuliza dawa rahisi.`, lines: [{who: `them`, pl: `Dzień dobry, słucham.`, sw: `Habari za mchana, nakusikiliza.`},{who: `you`, pl: `Dzień dobry, boli mnie głowa.`, sw: `Habari za mchana, kichwa kinaniuma.`},{who: `them`, pl: `Czy ma pan gorączkę?`, sw: `Je, bwana ana homa?`},{who: `you`, pl: `Nie, nie mam gorączki.`, sw: `Hapana, sina homa.`},{who: `them`, pl: `Czy ma pan alergię?`, sw: `Je, bwana ana mzio?`},{who: `you`, pl: `Nie mam alergii.`, sw: `Sina mzio.`},{who: `them`, pl: `Polecam ten lek.`, sw: `Ninapendekeza dawa hii.`},{who: `you`, pl: `Jak często mam brać?`, sw: `Nichukue mara ngapi?`},{who: `them`, pl: `Dwa razy dziennie po jedzeniu.`, sw: `Mara mbili kwa siku baada ya chakula.`},{who: `you`, pl: `Dziękuję, ile kosztuje?`, sw: `Asante, inagharimu kiasi gani?`},{who: `them`, pl: `Dwanaście złotych.`, sw: `Zloty kumi na mbili.`}]},{id: 8, title: `Mazungumzo madogo na mwenyeji`, scene: `Uko kwenye treni kutoka Kraków kwenda Warsaw. Mtu wa karibu anaanzisha mazungumzo ya kirafiki kuhusu safari yako Poland.`, lines: [{who: `you`, pl: `Dzień dobry, czy to miejsce jest wolne?`, sw: `Habari za mchana, je, kiti hiki kiko wazi?`},{who: `them`, pl: `Tak, proszę.`, sw: `Ndiyo, karibu.`},{who: `you`, pl: `Dziękuję.`, sw: `Asante.`},{who: `them`, pl: `Skąd jesteś?`, sw: `Unatoka wapi?`},{who: `you`, pl: `Jestem z Tanzanii.`, sw: `Ninatoka Tanzania.`},{who: `them`, pl: `Pierwszy raz w Polsce?`, sw: `Ni mara ya kwanza Poland?`},{who: `you`, pl: `Tak, pierwszy raz.`, sw: `Ndiyo, mara ya kwanza.`},{who: `them`, pl: `Jak podoba ci się Kraków?`, sw: `Kraków inakupendeza vipi?`},{who: `you`, pl: `Bardzo mi się podoba.`, sw: `Inanipendeza sana.`},{who: `them`, pl: `Lubisz polskie jedzenie?`, sw: `Unapenda chakula cha Kipolishi?`},{who: `you`, pl: `Tak, lubię pierogi.`, sw: `Ndiyo, napenda pierogi.`},{who: `them`, pl: `To dobry wybór.`, sw: `Huo ni uchaguzi mzuri.`}]}];